import { useState, useRef, useCallback } from "react";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const PRESET_CROPS = [
  { label: "ต้นฉบับ",  w: 0,    h: 0    },
  { label: "1:1",       ratio: 1              },
  { label: "4:3",       ratio: 4/3            },
  { label: "16:9",      ratio: 16/9           },
  { label: "ครึ่งบน",  region: "top"         },
  { label: "ครึ่งล่าง", region: "bottom"     },
];

function useCrop(naturalSize) {
  const [crop, setCrop]       = useState(null);
  const [dragging, setDragging] = useState(false);
  const startRef = useRef(null);

  const getPos = (e, el) => {
    const rect  = el.getBoundingClientRect();
    const touch = e.touches?.[0] ?? e;
    const x = Math.max(0, Math.min(touch.clientX - rect.left, rect.width));
    const y = Math.max(0, Math.min(touch.clientY - rect.top,  rect.height));
    return { x, y };
  };

  const onStart = (e, el) => {
    e.preventDefault();
    const pos = getPos(e, el);
    startRef.current = pos;
    setCrop({ x: pos.x, y: pos.y, x2: pos.x, y2: pos.y });
    setDragging(true);
  };
  const onMove = (e, el) => {
    if (!dragging || !startRef.current) return;
    e.preventDefault();
    const pos = getPos(e, el);
    setCrop({
      x:  Math.min(startRef.current.x, pos.x),
      y:  Math.min(startRef.current.y, pos.y),
      x2: Math.max(startRef.current.x, pos.x),
      y2: Math.max(startRef.current.y, pos.y),
    });
  };
  const onEnd = () => setDragging(false);
  const reset = () => { setCrop(null); startRef.current = null; };

  // แปลง pixel ของ element → pixel ของภาพจริง
  const toImageCoords = (elW, elH) => {
    if (!crop || !naturalSize) return null;
    const sx = naturalSize.w / elW;
    const sy = naturalSize.h / elH;
    return {
      x: Math.round(crop.x  * sx),
      y: Math.round(crop.y  * sy),
      w: Math.round((crop.x2 - crop.x) * sx),
      h: Math.round((crop.y2 - crop.y) * sy),
    };
  };

  return { crop, onStart, onMove, onEnd, reset, toImageCoords };
}

export default function ClassifyPage() {
  const [file,       setFile]       = useState(null);
  const [preview,    setPreview]    = useState(null);
  const [naturalSize, setNaturalSize] = useState(null);
  const [adj, setAdj]  = useState({ brightness: 1, contrast: 1, color: 1 });
  const [result,     setResult]     = useState(null);
  const [loading,    setLoading]    = useState(false);
  const [error,      setError]      = useState("");

  const cropAreaRef = useRef(null);
  const { crop, onStart, onMove, onEnd, reset: resetCrop, toImageCoords } = useCrop(naturalSize);

  const handleFile = (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setFile(f);
    setResult(null);
    setError("");
    resetCrop();

    const url = URL.createObjectURL(f);
    setPreview(url);
    const img = new Image();
    img.onload = () => setNaturalSize({ w: img.naturalWidth, h: img.naturalHeight });
    img.src = url;
  };

  const applyPreset = (preset) => {
    if (!naturalSize) return;
    resetCrop();
    // preset จะถูกส่งเป็น crop_x/y/w/h โดย handleSubmit อ่าน cropAreaRef
  };

  const handleSubmit = async () => {
    if (!file) return;
    setLoading(true);
    setError("");
    setResult(null);

    const el     = cropAreaRef.current;
    const coords = el ? toImageCoords(el.clientWidth, el.clientHeight) : null;

    const form = new FormData();
    form.append("file",       file);
    form.append("brightness", adj.brightness);
    form.append("contrast",   adj.contrast);
    form.append("color",      adj.color);
    if (coords) {
      form.append("crop_x", coords.x);
      form.append("crop_y", coords.y);
      form.append("crop_w", coords.w);
      form.append("crop_h", coords.h);
    }

    try {
      const res  = await fetch(`${API_URL}/api/ai/classify`, { method: "POST", body: form });
      const data = await res.json();
      if (data.error) { setError(data.error); return; }
      setResult(data);
    } catch {
      setError("เชื่อมต่อ server ไม่ได้");
    } finally {
      setLoading(false);
    }
  };

  const imgFilter = `brightness(${adj.brightness}) contrast(${adj.contrast}) saturate(${adj.color})`;

  return (
    <div style={{ padding: 24, maxWidth: 900, display: "grid", gridTemplateColumns: "1fr 320px", gap: 24 }}>

      {/* ── ซ้าย: ภาพ + crop ── */}
      <div>
        <h2 style={{ marginBottom: 16 }}>จำแนกประเภทภาพ</h2>
        <input type="file" accept="image/*" onChange={handleFile} style={{ marginBottom: 12 }} />

        {preview && (
          <>
            {/* crop presets */}
            <div style={{ display: "flex", gap: 6, marginBottom: 8, flexWrap: "wrap" }}>
              {PRESET_CROPS.map((p) => (
                <button key={p.label} onClick={() => { resetCrop(); }} style={{ fontSize: 12, padding: "4px 10px", borderRadius: 4, border: "1px solid #ccc", background: "#fff", cursor: "pointer" }}>
                  {p.label}
                </button>
              ))}
              {crop && (
                <button onClick={resetCrop} style={{ fontSize: 12, padding: "4px 10px", borderRadius: 4, border: "1px solid #e24b4a", color: "#e24b4a", background: "#fff", cursor: "pointer" }}>
                  ล้าง crop
                </button>
              )}
            </div>
            <p style={{ fontSize: 12, color: "#888", marginBottom: 6 }}>ลากบนภาพเพื่อเลือกพื้นที่</p>

            {/* crop area */}
            <div
              ref={cropAreaRef}
              style={{ position: "relative", cursor: "crosshair", userSelect: "none", borderRadius: 8, overflow: "hidden", lineHeight: 0, touchAction: "none" }}
              onMouseDown={(e) => onStart(e, cropAreaRef.current)}
              onMouseMove={(e) => onMove(e, cropAreaRef.current)}
              onMouseUp={onEnd}
              onTouchStart={(e) => onStart(e, cropAreaRef.current)}
              onTouchMove={(e) => onMove(e, cropAreaRef.current)}
              onTouchEnd={onEnd}
            >
              <img
                src={preview}
                alt="preview"
                style={{ width: "100%", display: "block", filter: imgFilter, pointerEvents: "none" }}
                draggable={false}
              />
              {/* crop overlay */}
              {crop && (
                <>
                  <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.35)", pointerEvents: "none" }} />
                  <div style={{
                    position: "absolute",
                    left: crop.x, top: crop.y,
                    width: crop.x2 - crop.x,
                    height: crop.y2 - crop.y,
                    border: "2px solid #fff",
                    boxShadow: "0 0 0 9999px rgba(0,0,0,0.35)",
                    pointerEvents: "none",
                  }} />
                </>
              )}
            </div>
          </>
        )}
      </div>

      {/* ── ขวา: sliders + ผลลัพธ์ ── */}
      <div>
        {/* sliders */}
        {preview && (
          <div style={{ background: "#f9f9f9", borderRadius: 8, padding: 16, marginBottom: 16 }}>
            <p style={{ fontWeight: 500, marginBottom: 12 }}>ปรับภาพ</p>
            {[
              { key: "brightness", label: "ความสว่าง",  min: 0.2, max: 2,  step: 0.05 },
              { key: "contrast",   label: "ความคมชัด",  min: 0.2, max: 2,  step: 0.05 },
              { key: "color",      label: "สี",          min: 0,   max: 2,  step: 0.05 },
            ].map(({ key, label, min, max, step }) => (
              <div key={key} style={{ marginBottom: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                  <span>{label}</span>
                  <span style={{ color: "#666" }}>{adj[key].toFixed(2)}</span>
                </div>
                <input
                  type="range" min={min} max={max} step={step}
                  value={adj[key]}
                  onChange={(e) => setAdj({ ...adj, [key]: parseFloat(e.target.value) })}
                  style={{ width: "100%" }}
                />
              </div>
            ))}
            <button
              onClick={() => setAdj({ brightness: 1, contrast: 1, color: 1 })}
              style={{ fontSize: 12, color: "#666", background: "none", border: "1px solid #ccc", borderRadius: 4, padding: "4px 10px", cursor: "pointer" }}
            >
              รีเซ็ต
            </button>
          </div>
        )}

        <button
          onClick={handleSubmit}
          disabled={!file || loading}
          style={{ width: "100%", padding: "10px 0", background: "#2196f3", color: "#fff", border: "none", borderRadius: 6, fontSize: 14, cursor: "pointer", marginBottom: 16, opacity: (!file || loading) ? 0.6 : 1 }}
        >
          {loading ? "กำลังวิเคราะห์..." : "วิเคราะห์ภาพ"}
        </button>

        {error && <p style={{ color: "red", fontSize: 13 }}>{error}</p>}

        {/* ผลลัพธ์ */}
        {result && (
          <div>
            {/* preview หลัง crop+adjust */}
            {result.preview && (
              <div style={{ marginBottom: 12 }}>
                <p style={{ fontSize: 12, color: "#666", marginBottom: 4 }}>ภาพที่ส่งไปวิเคราะห์</p>
                <img src={`data:image/jpeg;base64,${result.preview}`} alt="analyzed"
                  style={{ width: "100%", borderRadius: 6 }} />
              </div>
            )}

            {/* top result */}
            {result.top && (
              <div style={{ background: "#e8f5e9", padding: 12, borderRadius: 8, marginBottom: 12 }}>
                <p style={{ fontWeight: 600, fontSize: 16, margin: 0 }}>{result.top.label}</p>
                <p style={{ fontSize: 13, color: "#555", margin: "4px 0 8px" }}>{result.top.confidence.toFixed(1)}%</p>
                <div style={{ height: 6, background: "#c8e6c9", borderRadius: 3 }}>
                  <div style={{ height: "100%", width: `${result.top.confidence}%`, background: "#4caf50", borderRadius: 3 }} />
                </div>
              </div>
            )}

            {/* top 5 */}
            {result.results?.slice(1).map((r, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                <span style={{ width: 140, fontSize: 12, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.label}</span>
                <div style={{ flex: 1, height: 5, background: "#eee", borderRadius: 3 }}>
                  <div style={{ height: "100%", width: `${r.confidence}%`, background: "#90caf9", borderRadius: 3 }} />
                </div>
                <span style={{ fontSize: 11, color: "#666", width: 36, textAlign: "right" }}>{r.confidence.toFixed(1)}%</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
